\ \approx\
\frac{1}{2}\Delta\theta_M^\top F_M\,\Delta\theta_M,
\label{eq:kl_fisher_quadratic_restricted}
\end{equation}
where $F_M:=F_{MM}$ is the principal submatrix restricted to coordinates in $M$.
