\end{equation}
Because the same frozen head is used for all candidates, $\widehat D_{\mathrm{ref}}$ is directly comparable across different $M$.
\paragraph{Dual-output drift (optional).}
When the output head is trainable, raw output drift mixes backbone and head changes.
We separate these effects by evaluating the same hidden states under two heads:
\begin{equation}
p^0_\theta(\cdot|x,t)=\mathrm{softmax}\!\left(h_\theta(x,t)W_0^\top+b_0\right),
\qquad
p^\theta_\theta(\cdot|x,t)=\mathrm{softmax}\!\left(h_\theta(x,t)W_\theta^\top+b_\theta\right),
\label{eq:p_dual}
\end{equation}
and defining a head-induced mismatch measure
\begin{equation}
\widehat D_{\mathrm{dual}}(\theta)
:=
\mathbb{E}_{x\in\mathcal{X}_{\mathrm{probe}},\,t}
\Big[
\mathrm{JS}\big(p^\theta_\theta(\cdot|x,t)\ \|\ p^0_\theta(\cdot|x,t)\big)
\Big].
\label{eq:D_dual}
\end{equation}
In this setting, $\widehat D_{\mathrm{ref}}$ isolates backbone-induced drift in a fixed readout basis, while
$\widehat D_{\mathrm{dual}}$ quantifies the additional change introduced by the trained head conditioned on the same backbone states.
\subsection{Matched-drift selection rule}
\label{subsec:subset_selection}
Let $\mathcal{M}$ be a candidate family of trainable subsets.
For each $M\in\mathcal{M}$, we run a short tuning trajectory $\{\theta^{(k)}(M)\}_{k\ge 0}$ from $\theta^{(0)}(M)=\theta_0$
where only parameters in $M$ are trainable (endpoints fixed in the default setting).
We stop when the measured drift reaches a preset budget $\delta$:
\begin{equation}
\tau(M)
\ :=\
\min\Big\{k\ge 0:\ \widehat D_{\mathrm{ref}}\big(\theta^{(k)}(M)\big)\ \ge\ \delta\Big\}.
\label{eq:stopping_time_tau}
\end{equation}
We then score $M$ by its improvement on a held-out evaluation metric $\mathcal{E}(\theta)$ (lower is better) at matched drift:
\begin{equation}
\mathrm{Score}(M;\delta)
\ :=\
\mathcal{E}(\theta_0)\ -\ \mathcal{E}\big(\theta^{(\tau(M))}(M)\big).
\label{eq:score_matched_drift}
\end{equation}
When the output head is trainable, we optionally discard candidates with large head-induced change by requiring
$\widehat D_{\mathrm{dual}}\big(\theta^{(\tau(M))}(M)\big)\le \delta_{\mathrm{dual}}$.
\paragraph{Interpretation via drift-normalized local descent (analysis).}
In the near-reference regime, matched-drift selection is consistent with comparing candidates by drift-normalized descent directions.
Let $g:=\nabla\mathcal{T}(\theta)\vert_{\theta_0}$ and let $g_M$ be its restriction to $M$.
Using the Fisher local metric in Eq.~\eqref{eq:kl_fisher_local}, the best \emph{first-order} decrease in $\mathcal T$ within subset $M$
under budget $\delta$ solves
\begin{equation}
\min_{\Delta\theta_M}\ g_M^\top \Delta\theta_M
\quad \text{s.t.}\quad
\frac12\Delta\theta_M^\top F_M\Delta\theta_M\le \delta,
\label{eq:local_trust_region_M}
\end{equation}
whose optimal value is $-\sqrt{2\delta}\,\|g_M\|_{(F_M+\lambda I)^{-1}}$ under a damped metric $F_M+\lambda I$
(details in Appendix). This motivates selecting candidates that achieve larger improvement at the same drift.
\subsection{Two-stage schedules: solver choice, not oracle improvement}
\label{subsec:two_stage_clean_rewrite}
Finally, we clarify the role of two-stage schedules.
Two-stage does not change the subset $M$ and therefore does not change the oracle best-achievable value within that subset.
Its purpose is to reduce \emph{restricted optimization error} under practical training.
\paragraph{A second-order proxy for solver behavior.}
To model optimization difficulty beyond the first-order term, we consider a local quadratic proxy on $M$,
\begin{equation}
\Phi(\Delta\theta_M)
:=
g_M^\top \Delta\theta_M
+\frac12 \Delta\theta_M^\top (H_M+\beta(F_M+\lambda I))\Delta\theta_M,
\label{eq:phi_def_rewrite}
\end{equation}
where $H_M$ is a local curvature matrix on $M$, $\beta>0$ sets the drift scale, and $\lambda\ge 0$ is a damping term.
Let $M=M_{\mathrm{low}}\cup M_{\mathrm{high}}$ (two contiguous segments) and partition $\Delta\theta_M=(\Delta\theta_L,\Delta\theta_H)$.
Write $H_M+\beta(F_M+\lambda I)=\begin{psmallmatrix} A & C\\ C^\top & B\end{psmallmatrix}$.
\begin{proposition}[Coupling-induced correction captured by the second stage]
\label{prop:two_stage_rewrite}
Assume $A\succ 0$ and $B\succ 0$.
Let $\Delta_L^{\ast}:=\arg\min_{\Delta\theta_L}\Phi(\Delta\theta_L,0)$.
Fixing $\Delta\theta_L=\Delta_L^{\ast}$, the stage-2 conditional minimizer over the upper segment is
\begin{equation}
\Delta_H^{\ast}
\ =\
-B^{-1}\big(g_H + C^\top \Delta_L^{\ast}\big),
\label{eq:deltaH_star_full}
\end{equation}
where $g_H$ is the restriction of $g_M$ to the upper segment.
We can decompose $\Delta_H^{\ast}$ into a ``direct'' gradient component and a \emph{coupling-induced correction}:
\begin{equation}
\Delta_H^{\ast}
\ =\
\underbrace{-B^{-1}g_H}_{\text{direct upper-segment update}}
\ +\
\underbrace{\Delta_H^{\mathrm{corr}}}_{\text{coupling-induced correction}},
\qquad
\Delta_H^{\mathrm{corr}}:=-B^{-1}C^\top \Delta_L^{\ast}.
\label{eq:deltaH_decomp}
\end{equation}
The objective decrease attributable \emph{specifically} to the coupling-induced correction (relative to taking only $-B^{-1}g_H$ in stage 2)
is
\begin{equation}
\Phi(\Delta_L^{\ast},-B^{-1}g_H)\ -\ \Phi(\Delta_L^{\ast},\Delta_H^{\ast})
\ =\
\frac12\big\|B^{-1/2}C^\top \Delta_L^{\ast}\big\|_2^2.
\label{eq:two_stage_gain_rewrite}
\end{equation}
\end{proposition}
\noindent
Proposition~\ref{prop:two_stage_rewrite} does \emph{not} claim that two-stage improves the oracle optimum compared to joint optimization.
Instead, it isolates the coupling-induced \emph{correction term} $\Delta_H^{\mathrm{corr}}$ that becomes necessary once the lower segment has moved.
This motivates two-stage schedules as a practical solver: when the segments are coupled ($C\neq 0$), staged optimization can explicitly absorb
the correction induced by stage 1, improving attainability under noisy/finite-budget optimization.
\paragraph{Two-segment family.}
A practical structured family is the two-segment form
$M(x,y)=\{1,\dots,x\}\cup\{y,\dots,L\}$ (bottom block + top block), which contains $O(L^2)$ candidates.
For moderate $L$, this is already manageable, and we further reduce cost via coarse-to-fine screening:
we first scan a coarse grid of endpoints $(x,y)$ with stride $s$ (e.g., $s\in\{8,16\}$ for $L{=}96$) to identify promising regions under
Eq.~\eqref{eq:score_matched_drift}, and then refine locally around the best candidates with smaller strides.
In practice, this yields a small number of warmup runs while preserving the comparability guarantees provided by matched-drift evaluation.

