\section{Near-Reference Drift-Budgeted SFT: Theory}
\label{sec:nearref_lst_theory}
We study a regime of \emph{near-reference drift-budgeted SFT}: improving a target supervised objective while limiting functional drift from a strong reference checkpoint $\theta_0$.
Let $\pi_\theta(\cdot|x)$ denote the model distribution.
We consider supervised fine-tuning (SFT) with dataset $\mathcal D$,
\begin{equation}
\mathcal{T}(\theta)
\ :=\
\mathbb{E}_{(x,y^*)\sim\mathcal{D}}[-\log \pi_{\theta}(y^*|x)],
\label{eq:tsft_def}
\end{equation}
and measure functional drift from the reference model via
\begin{equation}
D_{\mathrm{ref}}(\theta)
\ :=\
\mathbb{E}_{x}\Big[\mathrm{KL}\big(\pi_{\theta}(\cdot|x)\ \|\ \pi_{\theta_0}(\cdot|x)\big)\Big].
\label{eq:dref_def}
\end{equation}
Our goal is to solve the drift-budgeted problem
\begin{equation}
\min_{\theta\in\Theta}\ \mathcal{T}(\theta)
\qquad \text{s.t.}\qquad
D_{\mathrm{ref}}(\theta)\le \delta,
\label{eq:drift_budget_problem}
\end{equation}
where $\Theta$ denotes the update class.
We focus on \emph{layer-selective tuning (LST)}, which restricts updates to a subset of blocks $M$ ($\theta_{\neg M}\equiv \theta_{0,\neg M}$).
This coordinate restriction yields a direct local geometry under KL drift.

\subsection{Local drift geometry and drift-normalized improvement}
\label{subsec:lst_local_geometry}
Around $\theta_0$, KL drift induces a Fisher quadratic form.
Let $F$ denote the Fisher information matrix of $\pi_{\theta_0}$ (under the input distribution of Eq.~\eqref{eq:dref_def}).
\begin{lemma}[Local quadratic approximation]
\label{lem:kl_fisher}
For $\theta=\theta_0+\Delta\theta$ in a sufficiently small neighborhood of $\theta_0$,
\begin{equation}
D_{\mathrm{ref}}(\theta_0+\Delta\theta)
\ \approx\
\frac{1}{2}\Delta\theta^\top F\,\Delta\theta.
\label{eq:kl_fisher_quadratic}
\end{equation}
Under LST, this reduces to $\frac{1}{2}\Delta\theta_M^\top F_M\,\Delta\theta_M$, where $F_M$ is the principal submatrix on $M$.
\end{lemma}
Let $g_M$ be the restriction of the task gradient $\nabla\mathcal{T}(\theta)\vert_{\theta_0}$ to $M$.
\begin{lemma}[Best first-order SFT improvement within LST]
\label{lem:budgeted_improvement}
Assume $F_M\succ 0$. The optimal value of the local drift-budgeted subproblem
$\min_{\Delta\theta_M} \{g_M^\top \Delta\theta_M \mid \frac{1}{2}\Delta\theta_M^\top F_M\Delta\theta_M\le \delta\}$ is
\begin{equation}
-\sqrt{2\delta}\,\|g_M\|_{F_M^{-1}},
\label{eq:local_improvement_value}
\end{equation}
achieved by $\Delta\theta_M \propto -F_M^{-1}g_M$.
\end{lemma}
\noindent
In practice, we use a damped metric $(F_M+\lambda I)$ for numerical stability.
Lemma~\ref{lem:budgeted_improvement} implies that for a given budget $\delta$, the potential improvement of a subset $M$ is governed by the drift-normalized signal norm $\|g_M\|_{F_M^{-1}}$.

\subsection{Decomposing performance limits}
\label{subsec:restriction_vs_optimization}
The performance of LST is limited by two distinct factors:
\begin{enumerate}
    \item \textbf{Subset Capacity (Restriction Gap):} Even with an ideal solver, restricting updates to $M$ limits reachable descent directions. Lemma~\ref{lem:budgeted_improvement} quantifies this capacity: if $M$ captures the drift-efficient directions of the gradient, $\|g_M\|_{F_M^{-1}}$ will be large. This motivates our subset selection method.
    \item \textbf{Optimization Error:} Given a subset $M$, a practical solver may fail to reach the oracle optimum $\mathcal{T}^{\star}_{\mathrm{LST}}(\delta;M)$ within the budget. This motivates our two-stage solver design to handle parameter coupling.
\end{enumerate}

